async function enhancePrompt(inputs, context) {
  const { basePrompt } = inputs;
  const enhancedPrompt = [
    `概念：${basePrompt}`,
    '输出：明确交付物、画幅/视口、文件或媒介',
    '风格：最多 1-2 个主风格，必要时写明 70/30 融合比例',
    '构图：主焦点、层级、网格、第一屏或画面边界',
    '光线/相机/空间：仅在相关时指定镜头、景深、光源与空间关系',
    '材质/细节：2-4 个服务主题的微观细节',
    '色彩/物理：色彩绑定情绪，材料遵守光照、反射、受力或运动规则',
    '禁止：无文字错误、无水印、无重叠、无低清晰度、无脱离需求的模板化输出',
    '验证：检查可读性、响应式、真实资产、链接/交互和最终文件'
  ].join('\n');
  return { enhancedPrompt };
}
